import{_ as e,o as d,c as a,a2 as r}from"./chunks/framework.CH-YxFqP.js";const y=JSON.parse('{"title":"Relay","description":"","frontmatter":{},"headers":[],"relativePath":"reference/relay.md","filePath":"reference/relay.md","lastUpdated":1781350447000}'),o={name:"reference/relay.md"};function l(c,t,i,s,n,h){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="relay" tabindex="-1">Relay <a class="header-anchor" href="#relay" aria-label="Permalink to &quot;Relay&quot;">​</a></h1><p>Relay 隧道通过 Agent 到 Agent 的路径承载流量。</p><p>它通常和 HTTP 规则或 L4 规则组合使用：规则负责监听入口和定义最终后端，Relay 监听器负责把中间路径串起来。</p><p>支持的传输模式包括：</p><ul><li><code>tls_tcp</code></li><li><code>quic</code></li><li><code>wireguard</code></li></ul><p>当传输路径需要经过托管的 WireGuard 接口时，Relay 可以与 WireGuard Profile 组合使用。</p><h2 id="监听器字段" tabindex="-1">监听器字段 <a class="header-anchor" href="#监听器字段" aria-label="Permalink to &quot;监听器字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>监听器在面板中的显示名称。</td></tr><tr><td>绑定地址</td><td>Agent 本机监听地址，可一行一个。</td></tr><tr><td>监听端口</td><td>Agent 本机监听端口。</td></tr><tr><td>公网入口</td><td>其他节点访问这条 Relay 时使用的地址，可填 <code>host</code> 或 <code>host:port</code>。</td></tr><tr><td>监听证书来源</td><td>默认使用自动签发的 Relay CA。</td></tr><tr><td>信任策略</td><td>默认自动使用 Relay CA + Pin。</td></tr><tr><td>Relay Transport</td><td><code>tls_tcp</code>、<code>quic</code> 或 <code>wireguard</code>。</td></tr></tbody></table><h2 id="传输模式" tabindex="-1">传输模式 <a class="header-anchor" href="#传输模式" aria-label="Permalink to &quot;传输模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>适用场景</th></tr></thead><tbody><tr><td><code>tls_tcp</code></td><td>默认模式，最容易先跑通。</td></tr><tr><td><code>quic</code></td><td>需要更低握手耗时，且 UDP/QUIC 链路可用。</td></tr><tr><td><code>wireguard</code></td><td>Relay 传输路径需要走托管 WireGuard Profile。</td></tr></tbody></table><p><code>wireguard</code> 只改变 Relay 传输路径，Relay 原有 TLS、mux、认证仍然生效。</p><h2 id="relay-层" tabindex="-1">Relay 层 <a class="header-anchor" href="#relay-层" aria-label="Permalink to &quot;Relay 层&quot;">​</a></h2><p>HTTP 规则和 L4 规则使用 <code>relay_layers</code> 表示链路。每一层可以包含多个 Relay 监听器，代表同一层的并行候选；多层会按顺序转发：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 -&gt; 第 1 层 -&gt; 第 2 层 -&gt; 后端</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>旧的 <code>relay_chain</code> 只作为兼容字段保留，新配置应使用 <code>relay_layers</code>。</p><h2 id="超时变量" tabindex="-1">超时变量 <a class="header-anchor" href="#超时变量" aria-label="Permalink to &quot;超时变量&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>NRE_RELAY_DIAL_TIMEOUT</code></td><td><code>5s</code></td><td>Relay 上游拨号超时。</td></tr><tr><td><code>NRE_RELAY_HANDSHAKE_TIMEOUT</code></td><td><code>5s</code></td><td>Relay 握手超时。</td></tr><tr><td><code>NRE_RELAY_FRAME_TIMEOUT</code></td><td><code>5s</code></td><td>Relay 单帧读写超时。</td></tr><tr><td><code>NRE_RELAY_IDLE_TIMEOUT</code></td><td><code>2m</code></td><td>Relay 空闲连接超时。</td></tr></tbody></table>',17)])])}const _=e(o,[["render",l]]);export{y as __pageData,_ as default};
